import { useEffect, useMemo, useState } from "react";
import {
  ArrowLeft,
  ArrowRight,
  Archive,
  Check,
  CheckCircle,
  Clock,
  FileAudio,
  FileText,
  GearSix,
  Image,
  MagnifyingGlass,
  Pause,
  Play,
  Plus,
  Repeat,
  ShieldCheck,
  Sparkle,
  Trash,
  UploadSimple,
  WarningCircle,
  X,
} from "@phosphor-icons/react";
import { useAuth } from "../auth/AuthContext.jsx";
import {
  FILE_SCENARIOS,
  INGESTION_STAGES,
  INGESTION_STATUSES,
  REVIEWERS,
  SELECTED_INGESTION_KEY,
} from "./ingestionData.js";
import {
  calculateIngestionCompleteness,
  calculateMetadataReadiness,
  ingestionService,
} from "./ingestionService.js";

export const INGESTION_VIEWS = new Set([
  "artist-submissions",
  "artist-submission-new",
  "artist-submission-detail",
  "admin-ingestion",
  "admin-ingestion-new",
  "admin-ingestion-detail",
]);

const clone = (value) => JSON.parse(JSON.stringify(value));
const wizardSteps = ["Basic Track Details", "Audio Assets", "Creative Metadata", "Contributors", "Rights Declaration", "Lyrics and Artwork", "Delivery Assets", "Review", "Declarations", "Submit"];
const workspaceTabs = ["Overview", "Audio Assets", "Processing Jobs", "Metadata", "Contributors", "Rights Declaration", "Artwork and Lyrics", "Delivery Assets", "Technical Review", "Catalog Review", "Rights Readiness", "Search Readiness", "Revision Requests", "Internal Notes", "Activity", "Final Approval", "Publication"];

function StatusBadge({ status }) {
  return <span className={`ingestion-status status-${String(status).toLowerCase().replace(/[^a-z0-9]+/g, "-")}`}><span />{status}</span>;
}

function ReadinessCard({ label, readiness }) {
  return <article className="ingestion-readiness-card"><div><span>{label}</span><strong>{readiness.percentage}%</strong></div><div className="ingestion-meter"><span style={{ width: `${readiness.percentage}%` }} /></div><small>{readiness.ready ? "Ready" : readiness.blockers[0] || "Review required"}</small></article>;
}

function ProgressTracker({ record }) {
  const current = INGESTION_STAGES.indexOf(record.currentStage);
  return <ol className="ingestion-progress" aria-label="Ingestion stages">{INGESTION_STAGES.map((stage, index) => <li key={stage} className={index < current ? "complete" : index === current ? "current" : record.status.includes("Failed") && index === current ? "blocked" : "upcoming"}><span>{index < current ? <Check /> : index + 1}</span><strong>{stage}</strong></li>)}</ol>;
}

function PageHeader({ eyebrow, title, text, actions }) {
  return <header className="ingestion-page-header"><div><span className="eyebrow">{eyebrow}</span><h2>{title}</h2><p>{text}</p></div>{actions && <div className="ingestion-header-actions">{actions}</div>}</header>;
}

export function ArtistSubmissions({ navigate, showToast }) {
  const { user } = useAuth();
  const records = ingestionService.getIngestionByUser(user);
  return <section className="ingestion-page"><PageHeader eyebrow="Artist / rightsholder intake" title="Track Submissions" text="Create protected drafts, supply assets and declarations, respond to review requests, and follow each track through human review." actions={<button className="ingestion-primary" onClick={() => navigate("artist-submission-new")}><Plus /> New Track Submission</button>} /><div className="ingestion-legal-note"><ShieldCheck /><div><strong>Private until approved</strong><span>Uploads and declarations are simulated prototype data. Submission does not verify rights or guarantee catalog acceptance.</span></div></div>{records.length === 0 ? <div className="ingestion-empty"><FileAudio /><h3>No submissions yet</h3><p>Create a private draft to begin.</p></div> : <div className="artist-submission-grid">{records.map((record) => { const readiness = ingestionService.calculateReadiness(record); const outstanding = [...readiness.completeness.blockers, ...readiness.publication.blockers].slice(0, 2); return <article key={record.id}><div><StatusBadge status={record.status} /><span>{record.reference || "Draft reference pending"}</span></div><h3>{record.trackTitle}</h3><p>{record.artistName} · {record.currentStage}</p><div className="ingestion-meter"><span style={{ width: `${readiness.completeness.percentage}%` }} /></div><small>Updated {new Date(record.updatedAt).toLocaleDateString()}</small>{outstanding.map((item) => <div className="ingestion-warning" key={item}><WarningCircle />{item}</div>)}<button onClick={() => { window.localStorage.setItem(SELECTED_INGESTION_KEY, record.id); navigate(record.status === "Draft" ? "artist-submission-new" : "artist-submission-detail"); }}>Open submission <ArrowRight /></button></article>; })}</div>}</section>;
}

function WizardNav({ step, setStep }) {
  return <nav className="ingestion-wizard-nav" aria-label="Submission steps">{wizardSteps.map((label, index) => <button key={label} className={step === index + 1 ? "active" : step > index + 1 ? "complete" : ""} onClick={() => setStep(index + 1)}><span>{step > index + 1 ? <Check /> : index + 1}</span>{label}</button>)}</nav>;
}

const Field = ({ label, children, hint }) => <label className="ingestion-field"><span>{label}</span>{children}{hint && <small>{hint}</small>}</label>;
const MultiInput = ({ value = [], onChange, placeholder }) => <input value={value.join(", ")} placeholder={placeholder} onChange={(event) => onChange(event.target.value.split(",").map((item) => item.trim()).filter(Boolean))} />;

function BasicStep({ record, setRecord }) {
  const metadata = record.metadata;
  const set = (key, value) => setRecord({ ...record, metadata: { ...metadata, [key]: value } });
  return <div className="ingestion-form-grid"><Field label="Track title"><input value={metadata.title} onChange={(e) => set("title", e.target.value)} required /></Field><Field label="Alternate title"><input value={metadata.alternateTitle || ""} onChange={(e) => set("alternateTitle", e.target.value)} /></Field><Field label="Artist"><input value={metadata.artist} onChange={(e) => set("artist", e.target.value)} /></Field><Field label="Version"><select value={metadata.versionName} onChange={(e) => set("versionName", e.target.value)}>{["Original", "Radio Edit", "Instrumental", "Clean", "Acoustic", "Remix", "Live", "Alternate Mix"].map((item) => <option key={item}>{item}</option>)}</select></Field><Field label="Release status"><select value={metadata.releaseStatus} onChange={(e) => set("releaseStatus", e.target.value)}><option>Unreleased</option><option>Previously Released</option><option>Archive</option></select></Field><Field label="Album or release"><input value={metadata.album || ""} onChange={(e) => set("album", e.target.value)} /></Field><Field label="Release date"><input type="date" value={metadata.releaseDate || ""} onChange={(e) => set("releaseDate", e.target.value)} /></Field><Field label="Original release year"><input type="number" min="1900" max="2026" value={metadata.releaseYear || ""} onChange={(e) => set("releaseYear", e.target.value)} /></Field><Field label="Primary language"><select value={metadata.primaryLanguage} onChange={(e) => set("primaryLanguage", e.target.value)}><option>English</option><option>Spanish</option><option>French</option><option>Instrumental / none</option><option>Other</option></select></Field><Field label="Explicit content"><select value={metadata.explicit} onChange={(e) => set("explicit", e.target.value)}><option>Undeclared</option><option>Clean</option><option>Explicit</option><option>Instrumental</option></select></Field><Field label="ISRC (optional)"><input value={metadata.isrc || ""} onChange={(e) => set("isrc", e.target.value)} /></Field><Field label="Internal catalog code"><input value={metadata.catalogCode || ""} onChange={(e) => set("catalogCode", e.target.value)} /></Field><Field label="Short buyer-facing description"><textarea value={metadata.shortDescription || ""} onChange={(e) => set("shortDescription", e.target.value)} /></Field></div>;
}

function AudioStep({ record, refresh, showToast }) {
  const { user } = useAuth();
  const [scenario, setScenario] = useState("Valid WAV");
  const [replaceId, setReplaceId] = useState(null);
  const upload = () => { const result = ingestionService.uploadMockAsset(record.id, scenario, user, replaceId); showToast(result.ok ? `${result.asset.fileName} uploaded${result.warnings.length ? " with warnings" : ""}.` : result.message); if (result.ok) { setReplaceId(null); refresh(); } };
  return <><div className="ingestion-upload-simulator"><div><UploadSimple /><h3>Mock protected asset intake</h3><p>No file leaves this browser. Select a deterministic scenario to test validation and versioning.</p></div><Field label="Demo file scenario"><select value={scenario} onChange={(e) => setScenario(e.target.value)}>{Object.keys(FILE_SCENARIOS).map((item) => <option key={item}>{item}</option>)}</select></Field><button className="ingestion-primary" onClick={upload}>{replaceId ? "Upload replacement version" : "Upload simulated asset"}</button></div><div className="ingestion-asset-list">{record.assets.filter((item) => item.current).map((asset) => <article key={asset.id}><FileAudio /><div><strong>{asset.assetType}</strong><span>{asset.fileName} · v{asset.version} · {asset.fileSize}</span><small>{asset.sampleRate || "—"} · {asset.bitDepth || "—"} · {asset.channels || "—"}</small></div><StatusBadge status={asset.qualityStatus} /><progress max="100" value={asset.uploadProgress ?? 100} aria-label={`${asset.fileName} upload progress`} /><div><button onClick={() => setReplaceId(asset.id)}><Repeat /> Replace</button><button onClick={() => { ingestionService.removeAsset(record.id, asset.id, user); refresh(); }}><Trash /> Remove</button></div></article>)}</div>{record.assets.some((item) => !item.current) && <details className="ingestion-version-history"><summary>Prior asset versions</summary>{record.assets.filter((item) => !item.current).map((item) => <p key={item.id}>{item.fileName} · version {item.version} · {item.reviewResult}</p>)}</details>}</>;
}

function MetadataStep({ record, setRecord }) {
  const metadata = record.metadata;
  const set = (key, value) => setRecord({ ...record, metadata: { ...metadata, [key]: value } });
  const readiness = calculateMetadataReadiness(record);
  return <><ReadinessCard label="Metadata completeness" readiness={readiness} /><div className="ingestion-form-grid"><Field label="Primary genre"><select value={metadata.primaryGenre || ""} onChange={(e) => set("primaryGenre", e.target.value)}><option value="">Select genre</option>{["Alternative", "Indie Rock", "Pop", "Electronic", "Cinematic", "Soul", "R&B", "Folk", "Americana", "Ambient", "Rock", "Acoustic", "Synthwave", "Orchestral", "Experimental"].map((item) => <option key={item}>{item}</option>)}</select></Field><Field label="Moods" hint="Enter at least two, separated by commas"><MultiInput value={metadata.moods} onChange={(value) => set("moods", value)} placeholder="Uplifting, Reflective" /></Field><Field label="Intended usage"><MultiInput value={metadata.intendedUsage} onChange={(value) => set("intendedUsage", value)} placeholder="Advertising, Trailer" /></Field><Field label="Duration"><input value={metadata.duration || ""} placeholder="3:12" onChange={(e) => set("duration", e.target.value)} /></Field><Field label="Tempo"><select value={metadata.tempo || ""} onChange={(e) => set("tempo", e.target.value)}><option value="">Select</option><option>Slow</option><option>Mid-tempo</option><option>Uptempo</option><option>Variable</option></select></Field><Field label="BPM"><input type="number" min="20" max="240" value={metadata.bpm || ""} onChange={(e) => set("bpm", e.target.value)} /></Field><Field label="Key"><input value={metadata.key || ""} onChange={(e) => set("key", e.target.value)} /></Field><Field label="Energy"><select value={metadata.energy || ""} onChange={(e) => set("energy", e.target.value)}><option value="">Select</option><option>Low</option><option>Medium</option><option>High</option></select></Field><Field label="Vocal type"><select value={metadata.vocalType || ""} onChange={(e) => set("vocalType", e.target.value)}><option value="">Select</option>{["Instrumental", "Male Vocal", "Female Vocal", "Mixed Vocal", "Group Vocal", "Spoken Word", "Choir", "Vocal Texture", "No Lead Vocal"].map((item) => <option key={item}>{item}</option>)}</select></Field><Field label="Instrumentation"><textarea value={metadata.instrumentation || ""} onChange={(e) => set("instrumentation", e.target.value)} /></Field><Field label="Keywords"><MultiInput value={metadata.keywords} onChange={(value) => set("keywords", value)} placeholder="driving, premium, cinematic" /></Field><Field label="Editorial description"><textarea value={metadata.editorialDescription || ""} onChange={(e) => set("editorialDescription", e.target.value)} /></Field></div><section className="ingestion-extraction"><h3>Extracted file metadata</h3><p>Simulation only — review required.</p><dl><dt>Embedded title</dt><dd>{record.assets[0]?.fileName?.replace(/[-_]/g, " ") || "Not extracted"}</dd><dt>Duration</dt><dd>{record.assets[0]?.duration || "Not extracted"}</dd><dt>Suggested BPM</dt><dd>{metadata.bpm || "118"} · Automated suggestion — review required</dd><dt>Suggested key</dt><dd>{metadata.key || "A Minor"} · Automated suggestion — review required</dd></dl></section></>;
}

function ContributorsStep({ record, refresh, showToast }) {
  const { user } = useAuth(); const [form, setForm] = useState({ name: "", role: "Writer", contact: "", rightsPartyLink: "", creditWording: "", approvalRequired: false, notes: "" });
  return <><div className="ingestion-form-grid"><Field label="Contributor name"><input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} /></Field><Field label="Role"><select value={form.role} onChange={(e) => setForm({ ...form, role: e.target.value })}>{["Primary Artist", "Featured Artist", "Writer", "Composer", "Producer", "Mixer", "Mastering Engineer", "Session Performer", "Vocalist", "Remixer", "Other"].map((item) => <option key={item}>{item}</option>)}</select></Field><Field label="Contact (restricted)"><input value={form.contact} onChange={(e) => setForm({ ...form, contact: e.target.value })} /></Field><Field label="Rights party link"><input value={form.rightsPartyLink} onChange={(e) => setForm({ ...form, rightsPartyLink: e.target.value })} /></Field></div><button className="ingestion-primary" onClick={() => { const result = ingestionService.addContributor(record.id, form, user); showToast(result.ok ? "Contributor added." : result.message); if (result.ok) { setForm({ ...form, name: "" }); refresh(); } }}><Plus /> Add contributor</button><div className="ingestion-card-grid">{record.contributors.map((item) => <article key={item.id}><strong>{item.name}</strong><span>{item.role}</span><small>{item.rightsPartyLink || "No rights-party link"}</small></article>)}</div></>;
}

function RightsStep({ record, setRecord, saveRights }) {
  const declaration = record.rightsDeclaration || {};
  const set = (key, value) => { const updated = { ...declaration, [key]: value }; setRecord({ ...record, rightsDeclaration: updated }); saveRights(updated); };
  const yesNo = (key, label) => <Field label={label}><select value={declaration[key] || "Undeclared"} onChange={(e) => set(key, e.target.value)}><option>Undeclared</option><option>Yes</option><option>No</option></select></Field>;
  return <><div className="ingestion-rights-warning"><ShieldCheck /><div><strong>Declaration, not verification</strong><p>These answers create or update a linked draft rights record. Human rights review remains required.</p></div></div><div className="ingestion-form-grid">{yesNo("controlsMaster", "Do you control the master?")}<Field label="Master percentage controlled"><input type="number" min="0" max="100" value={declaration.masterPercentage || ""} onChange={(e) => set("masterPercentage", e.target.value)} /></Field>{yesNo("allWritersIdentified", "Are all writers identified?")}<Field label="Writer-share total"><input type="number" min="0" max="100" value={declaration.writerSharesTotal || ""} onChange={(e) => set("writerSharesTotal", e.target.value)} /></Field>{yesNo("publishersIdentified", "Are publishers identified?")}{yesNo("samplesUsed", "Are samples used?")}{yesNo("interpolationsUsed", "Are interpolations used?")}{yesNo("featuredArtists", "Are featured artists present?")}{yesNo("releasesAvailable", "Are contributor releases available?")}{yesNo("thirdPartyApproval", "Is third-party approval required?")}{yesNo("rightsDisputed", "Are any rights disputed?")}{yesNo("exclusiveAgreements", "Are there exclusive agreements?")}{yesNo("splitSheetAvailable", "Is a split sheet available?")}<Field label="Licensing restrictions"><textarea value={declaration.licensingRestrictions || ""} onChange={(e) => set("licensingRestrictions", e.target.value)} /></Field><Field label="Territory restrictions"><textarea value={declaration.territoryRestrictions || ""} onChange={(e) => set("territoryRestrictions", e.target.value)} /></Field></div>{record.rightsReadiness?.blockers?.map((item) => <div className="ingestion-warning" key={item}><WarningCircle />{item}</div>)}</>;
}

function ArtworkLyricsStep({ record, setRecord, uploadArtwork }) {
  return <div className="ingestion-two-column"><section className="ingestion-panel"><h3>Lyrics</h3><Field label="Lyrics state"><select value={record.lyrics.status} onChange={(e) => setRecord({ ...record, lyrics: { ...record.lyrics, status: e.target.value } })}><option>Not Provided</option><option>Provided</option><option>Instrumental</option><option>Unavailable</option></select></Field><Field label="Lyrics language"><input value={record.lyrics.language || ""} onChange={(e) => setRecord({ ...record, lyrics: { ...record.lyrics, language: e.target.value } })} /></Field><Field label="Paste lyrics"><textarea rows="10" value={record.lyrics.text || ""} onChange={(e) => setRecord({ ...record, lyrics: { ...record.lyrics, text: e.target.value, status: e.target.value ? "Provided" : record.lyrics.status } })} /></Field></section><section className="ingestion-panel"><h3>Artwork</h3><div className="artwork-placeholder" role="img" aria-label={`${record.trackTitle} submitted artwork preview`}><Image /></div><p>Square artwork of at least 1600 × 1600 is preferred.</p><button onClick={uploadArtwork}><UploadSimple /> Upload valid artwork simulation</button><dl><dt>Status</dt><dd>{record.artwork.status}</dd><dt>Resolution</dt><dd>{record.artwork.width ? `${record.artwork.width} × ${record.artwork.height}` : "Not supplied"}</dd></dl></section></div>;
}

function DeliveryStep({ record, setRecord }) {
  const options = ["Provided", "Not available", "Can be prepared", "Requires additional fee", "Under review", "Approved"];
  return <div className="delivery-assets-grid">{[["master", "WAV master"],["instrumental", "Instrumental"],["clean", "Clean version"],["acapella", "Acapella"],["stems", "Stems"],["alternateMix", "Alternate mix"],["thirtySecond", "30-second edit"],["sixtySecond", "60-second edit"],["fifteenSecond", "15-second edit"],["noVocal", "No-vocal edit"],["broadcastSafe", "Broadcast-safe edit"]].map(([key, label]) => <Field key={key} label={label}><select value={record.deliveryAssets[key] || "Not available"} onChange={(e) => setRecord({ ...record, deliveryAssets: { ...record.deliveryAssets, [key]: e.target.value } })}>{options.map((option) => <option key={option}>{option}</option>)}</select></Field>)}</div>;
}

function ReviewStep({ record }) {
  const readiness = ingestionService.calculateReadiness(record);
  return <><div className="ingestion-readiness-grid"><ReadinessCard label="Overall completeness" readiness={readiness.completeness} /><ReadinessCard label="Metadata" readiness={readiness.metadata} /><ReadinessCard label="Technical" readiness={readiness.technical} /><ReadinessCard label="Rights" readiness={readiness.rights} /><ReadinessCard label="Search" readiness={readiness.search} /><ReadinessCard label="Publication" readiness={readiness.publication} /></div><div className="ingestion-two-column"><section className="ingestion-panel"><h3>Blocking errors</h3>{readiness.completeness.blockers.length ? readiness.completeness.blockers.map((item) => <div className="ingestion-blocker" key={item}><WarningCircle />{item}</div>) : <p>No submission blockers.</p>}</section><section className="ingestion-panel"><h3>Submission package</h3><dl><dt>Assets</dt><dd>{record.assets.filter((item) => item.current).length}</dd><dt>Contributors</dt><dd>{record.contributors.length}</dd><dt>Artwork</dt><dd>{record.artwork.status}</dd><dt>Lyrics</dt><dd>{record.lyrics.status}</dd><dt>Rights</dt><dd>{record.rightsReadiness.status}</dd></dl></section></div></>;
}

function DeclarationsStep({ record, setRecord }) {
  const declarations = [["authorized", "I am authorized to submit this track."],["accurate", "The information provided is accurate."],["disclosed", "I have disclosed all known writers, owners, samples, and restrictions."],["reviewAllowed", "beatmondo may review and verify the submitted information."],["noGuarantee", "Submission does not guarantee catalog acceptance."],["additionalInfo", "beatmondo may request additional information."],["privateUntilApproved", "I understand files remain private until approved."]];
  return <div className="declaration-list">{declarations.map(([key, label]) => <label key={key}><input type="checkbox" checked={Boolean(record.declarations[key])} onChange={(e) => setRecord({ ...record, declarations: { ...record.declarations, [key]: e.target.checked } })} /><span>{label}</span></label>)}<small>Terms version INGESTION-DEMO-2026.1 · simulated browser session · {new Date().toLocaleDateString()}</small></div>;
}

export function TrackSubmissionWizard({ navigate, showToast, internalMode = false }) {
  const { user } = useAuth();
  const [draftId, setDraftId] = useState(() => window.localStorage.getItem(SELECTED_INGESTION_KEY));
  const [record, setRecord] = useState(null);
  const [step, setStep] = useState(1);
  const refresh = () => {
    const next = ingestionService.getById(draftId);
    setRecord(next);
  };
  useEffect(() => { let id = draftId; let existing = id ? ingestionService.getById(id) : null; if (!existing || existing.status !== "Draft") { const result = ingestionService.createDraft(user, internalMode ? "Internal Catalog" : "Artist Portal"); existing = result.draft; id = existing.id; window.localStorage.setItem(SELECTED_INGESTION_KEY, id); setDraftId(id); } setRecord(existing); setStep(existing.lastStep || 1); }, []);
  useEffect(() => { if (!record?.id) return; const timer = window.setTimeout(() => ingestionService.saveStep(record.id, step, { metadata: record.metadata, lyrics: record.lyrics, artwork: record.artwork, deliveryAssets: record.deliveryAssets, declarations: record.declarations }, user), 350); return () => window.clearTimeout(timer); }, [record, step]);
  if (!record) return <section className="ingestion-page"><div className="ingestion-empty">Preparing protected draft…</div></section>;
  const saveAndMove = (next) => { ingestionService.saveStep(record.id, next, { metadata: record.metadata, lyrics: record.lyrics, artwork: record.artwork, deliveryAssets: record.deliveryAssets, declarations: record.declarations }, user); setStep(next); window.scrollTo({ top: 0, behavior: "smooth" }); };
  const saveRights = (declaration) => { ingestionService.updateRightsDeclaration(record.id, declaration, user); const next = ingestionService.getById(record.id); setRecord((current) => ({ ...current, rightsReadiness: next.rightsReadiness })); };
  const content = step === 1 ? <BasicStep record={record} setRecord={setRecord} /> : step === 2 ? <AudioStep record={record} refresh={refresh} showToast={showToast} /> : step === 3 ? <MetadataStep record={record} setRecord={setRecord} /> : step === 4 ? <ContributorsStep record={record} refresh={refresh} showToast={showToast} /> : step === 5 ? <RightsStep record={record} setRecord={setRecord} saveRights={saveRights} /> : step === 6 ? <ArtworkLyricsStep record={record} setRecord={setRecord} uploadArtwork={() => { const result = ingestionService.uploadMockAsset(record.id, "Valid artwork", user); if (result.ok) { ingestionService.saveStep(record.id, step, { artwork: { status: "Uploaded", fileName: result.asset.fileName, width: 2400, height: 2400 } }, user); refresh(); } showToast(result.ok ? "Artwork uploaded for review." : result.message); }} /> : step === 7 ? <DeliveryStep record={record} setRecord={setRecord} /> : step === 8 ? <ReviewStep record={record} /> : step === 9 ? <DeclarationsStep record={record} setRecord={setRecord} /> : <section className="ingestion-submit-panel"><CheckCircle /><h3>Ready to enter human review?</h3><p>Submission creates processing jobs and a draft rights handoff. It does not publish the track.</p><button className="ingestion-primary" onClick={() => { ingestionService.saveStep(record.id, step, { metadata: record.metadata, lyrics: record.lyrics, artwork: record.artwork, deliveryAssets: record.deliveryAssets, declarations: record.declarations }, user); const result = ingestionService.submitIngestion(record.id, user); showToast(result.ok ? `${result.reference} submitted.` : result.message); if (result.ok) { window.localStorage.setItem(SELECTED_INGESTION_KEY, result.record.id); navigate(internalMode ? "admin-ingestion-detail" : "artist-submission-detail"); } }}>{internalMode ? "Submit internal draft" : "Submit for review"}</button></section>;
  return <section className="ingestion-page ingestion-wizard-page"><PageHeader eyebrow={internalMode ? "Internal catalog intake" : "Private artist submission"} title={record.metadata.title || "New Track Submission"} text={`Draft autosaves in this browser · Last saved ${new Date(record.updatedAt).toLocaleTimeString()}`} actions={<><button onClick={() => navigate(internalMode ? "admin-ingestion" : "artist-submissions")}>Save and exit</button><button className="danger" onClick={() => { if (window.confirm("Discard this draft and its current mock files?")) { const result = ingestionService.discardDraft(record.id, user); showToast(result.message); navigate(internalMode ? "admin-ingestion" : "artist-submissions"); } }}>Discard draft</button></>} /><div className="ingestion-wizard-layout"><WizardNav step={step} setStep={setStep} /><main className="ingestion-wizard-content"><div className="ingestion-step-heading"><span>Step {step} of 10</span><h3>{wizardSteps[step - 1]}</h3></div>{content}<div className="ingestion-step-actions">{step > 1 && <button onClick={() => saveAndMove(step - 1)}><ArrowLeft /> Previous</button>}{step < 10 && <button className="ingestion-primary" onClick={() => saveAndMove(step + 1)}>Save and continue <ArrowRight /></button>}</div></main></div></section>;
}

export function ArtistSubmissionDetail({ navigate, showToast }) {
  const { user } = useAuth(); const id = window.localStorage.getItem(SELECTED_INGESTION_KEY); const [record, setRecord] = useState(() => ingestionService.getById(id)); const [response, setResponse] = useState("");
  if (!record || (!user?.permissions?.includes("*") && record.organizationId !== user?.organizationId && record.submittedByUserId !== user?.id)) return <section className="ingestion-page"><div className="ingestion-empty"><WarningCircle /><h2>Submission unavailable</h2><p>You can open only your own private submissions.</p></div></section>;
  const readiness = ingestionService.calculateReadiness(record);
  return <section className="ingestion-page"><button className="ingestion-back" onClick={() => navigate("artist-submissions")}><ArrowLeft /> Track submissions</button><PageHeader eyebrow={record.reference || "Draft"} title={record.trackTitle} text={`${record.artistName} · ${record.currentStage}`} actions={<StatusBadge status={record.status} />} /><ProgressTracker record={record} /><div className="ingestion-readiness-grid"><ReadinessCard label="Completeness" readiness={readiness.completeness} /><ReadinessCard label="Technical" readiness={readiness.technical} /><ReadinessCard label="Rights" readiness={readiness.rights} /><ReadinessCard label="Search" readiness={readiness.search} /></div>{record.artistMessages.map((message) => <div className="ingestion-artist-message" key={message.id}><strong>Message from beatmondo</strong><p>{message.content}</p></div>)}{record.revisionRequests.filter((item) => item.status === "Open").map((revision) => <section className="ingestion-panel revision-response" key={revision.id}><StatusBadge status="Revision Requested" /><h3>{revision.title}</h3><p>{revision.artistMessage}</p><ul>{revision.affectedSections?.map((item) => <li key={item}>{item}</li>)}</ul><Field label="Response note"><textarea value={response} onChange={(e) => setResponse(e.target.value)} /></Field><button className="ingestion-primary" onClick={() => { const result = ingestionService.submitRevision(record.id, response, user); showToast(result.ok ? "Revision response submitted." : result.message); if (result.ok) setRecord(ingestionService.getById(record.id)); }}>Resubmit changes</button></section>)}<div className="ingestion-two-column"><section className="ingestion-panel"><h3>Outstanding actions</h3>{readiness.publication.blockers.length ? readiness.publication.blockers.slice(0, 8).map((item) => <div className="ingestion-warning" key={item}><WarningCircle />{item}</div>) : <p>No outstanding actions.</p>}</section><section className="ingestion-panel"><h3>Current package</h3><p>{record.assets.filter((item) => item.current).length} current assets · {record.contributors.length} contributors</p><p>Artwork: {record.artwork.status}</p><p>Lyrics: {record.lyrics.status}</p><p>Rights: {record.rightsReadiness.status}</p></section></div><section className="ingestion-panel"><h3>Submission activity</h3><div className="ingestion-timeline">{record.activity.filter((item) => item.visibility === "Artist Visible").map((item) => <article key={item.id}><span /><div><strong>{item.action}</strong><p>{item.description}</p><small>{item.actor} · {new Date(item.timestamp).toLocaleString()}</small></div></article>)}</div></section>{["Draft", "Revision Requested", "Metadata Incomplete", "Rights Information Required"].includes(record.status) && <button className="danger" onClick={() => { const result = ingestionService.withdraw(record.id, "Withdrawn from artist workspace", user); showToast(result.ok ? "Submission withdrawn." : result.message); if (result.ok) setRecord(ingestionService.getById(record.id)); }}>Withdraw submission</button>}</section>;
}

export function IngestionDashboard({ navigate, showToast }) {
  const { user } = useAuth(); const [filters, setFilters] = useState({ query: "", status: "All Statuses", currentStage: "All Stages", source: "All Sources", priority: "All Priorities", technical: "All Technical", rights: "All Rights" }); const [version, setVersion] = useState(0); const records = ingestionService.getQueue(filters, user); const analytics = ingestionService.getAnalytics();
  const open = (record) => { window.localStorage.setItem(SELECTED_INGESTION_KEY, record.id); navigate("admin-ingestion-detail"); };
  return <section className="ingestion-page"><PageHeader eyebrow="Catalog intake operations" title="Track Ingestion" text="Control protected assets, metadata, technical processing, creative review, rights handoff, search preparation, approval, and publication." actions={<><button onClick={() => navigate("admin-ingestion-new")}><Plus /> Internal draft</button>{user?.permissions?.includes("*") && <button onClick={() => { ingestionService.resetTrackIngestionDemoData(); setVersion(version + 1); showToast("Track Ingestion demo data reset."); }}>Reset ingestion demo</button>}</>} /><div className="ingestion-legal-note"><ShieldCheck /><div><strong>Human-reviewed prototype workflow</strong><span>No displayed scan, extraction, waveform, transcoding, watermark, or storage state represents a production security or media operation.</span></div></div><div className="ingestion-metrics">{[["Total submissions",analytics.total],["Drafts",analytics.drafts],["Files processing",analytics.processing],["Processing failures",analytics.failures],["Metadata incomplete",analytics.metadataIncomplete],["Technical review",analytics.technical],["Catalog review",analytics.catalog],["Rights review",analytics.rights],["Revision requested",analytics.revisions],["Awaiting approval",analytics.awaiting],["Published",analytics.published],["Rejected",analytics.rejected],["Published rate",`${analytics.publishedRate}%`],["Average completeness",`${analytics.averageCompleteness}%`],["Average ingestion",`${analytics.averageDays} days`],["Oldest unresolved",analytics.oldest]].map(([label,value]) => <article key={label}><span>{label}</span><strong>{value}</strong></article>)}</div><div className="ingestion-filters"><label><MagnifyingGlass /><input aria-label="Search ingestion queue" placeholder="Track, artist, reference, ISRC, or submitter" value={filters.query} onChange={(e) => setFilters({ ...filters, query: e.target.value })} /></label><select aria-label="Status filter" value={filters.status} onChange={(e) => setFilters({ ...filters, status: e.target.value })}><option>All Statuses</option>{Object.keys(INGESTION_STATUSES).map((item) => <option key={item}>{item}</option>)}</select><select aria-label="Stage filter" value={filters.currentStage} onChange={(e) => setFilters({ ...filters, currentStage: e.target.value })}><option>All Stages</option>{INGESTION_STAGES.map((item) => <option key={item}>{item}</option>)}</select><select aria-label="Source filter" value={filters.source} onChange={(e) => setFilters({ ...filters, source: e.target.value })}><option>All Sources</option><option>Artist Portal</option><option>Internal Catalog</option></select><select aria-label="Priority filter" value={filters.priority} onChange={(e) => setFilters({ ...filters, priority: e.target.value })}><option>All Priorities</option><option>Critical</option><option>Urgent</option><option>High</option><option>Standard</option></select></div><div className="ingestion-table-wrap"><table><thead><tr><th>Reference / Track</th><th>Status</th><th>Stage</th><th>Completeness</th><th>Technical</th><th>Rights</th><th>Search</th><th>Reviewer</th><th>Updated</th><th>Priority</th><th /></tr></thead><tbody>{records.map((record) => <tr key={record.id}><td><strong>{record.trackTitle}</strong><small>{record.artistName} · {record.reference || "Draft"} · {record.source}</small></td><td><StatusBadge status={record.status} /></td><td>{record.currentStage}</td><td><strong>{calculateIngestionCompleteness(record).percentage}%</strong></td><td>{record.qualityControl?.status}</td><td>{record.rightsReadiness?.status}</td><td>{record.searchReadiness?.status}</td><td>{REVIEWERS.find((item) => item.id === record.assignedCatalogReviewer)?.name || "Unassigned"}</td><td>{new Date(record.updatedAt).toLocaleDateString()}</td><td>{record.priority}</td><td><button onClick={() => open(record)}>Review</button></td></tr>)}</tbody></table></div></section>;
}

function JobsPanel({ record, refresh, showToast }) {
  const { user } = useAuth(); return <><div className="ingestion-actions"><button onClick={() => { const result = ingestionService.completeAllJobs(record.id, user); showToast(result.ok ? "All demo jobs completed." : result.message); refresh(); }}>Complete all jobs</button></div><div className="processing-job-list">{record.processingJobs.map((job) => <article key={job.id}><div><strong>{job.jobType}</strong><span>{job.failureMessage || job.result?.label || job.result || "Awaiting demo processing"}</span></div><StatusBadge status={job.status} /><progress max="100" value={job.progress} aria-label={`${job.jobType} progress`} /><div><button onClick={() => { ingestionService.runProcessingJob(record.id, job.id, user, "complete"); refresh(); }}>Run</button><button onClick={() => { ingestionService.runProcessingJob(record.id, job.id, user, "fail"); refresh(); }}>Fail</button>{job.status === "Failed" && <button onClick={() => { ingestionService.retryProcessingJob(record.id, job.id, user); refresh(); }}>Retry</button>}</div></article>)}</div>{record.processingJobs.find((job) => job.jobType === "Waveform generation" && job.result?.peaks) && <div className="ingestion-waveform" aria-label="Fixed-value prototype waveform">{record.processingJobs.find((job) => job.jobType === "Waveform generation").result.peaks.map((peak,index) => <span key={index} style={{ height: `${peak}%` }} />)}</div>}</>;
}

function ChecklistPanel({ type, record, refresh, showToast }) {
  const { user } = useAuth(); const source = type === "technical" ? record.qualityControl : record.catalogReview; const [checklist, setChecklist] = useState(source.checklist || {}); const [decision, setDecision] = useState(type === "technical" ? "Passed" : "Approve"); const [reason, setReason] = useState(""); const labels = type === "technical" ? ["File opens","Format acceptable","Duration valid","Sample rate acceptable","Bit depth acceptable","Channels approved","No clipping detected — simulated","No unintended silence","No corruption","Master matches metadata","Preview source selected","Stems readable","Filename acceptable"] : ["Artist identity confirmed","Track title confirmed","Catalog fit","Production quality","Metadata quality","Genre classification","Mood classification","Usage classification","Artwork quality","Lyrics reviewed","Explicit-content state","Similar tracks","Editorial description","Buyer relevance","Duplicate track check"];
  const keys = Object.keys(checklist).length ? Object.keys(checklist) : labels.map((label) => label.toLowerCase().replace(/[^a-z]+/g,"_"));
  return <><div className="review-checklist">{keys.map((key,index) => <label key={key}><input type="checkbox" checked={Boolean(checklist[key])} onChange={(e) => setChecklist({ ...checklist, [key]: e.target.checked })} /><span>{labels[index] || key}</span></label>)}</div><div className="ingestion-form-grid"><Field label="Decision"><select value={decision} onChange={(e) => setDecision(e.target.value)}>{(type === "technical" ? ["Passed","Passed with Warnings","Failed"] : ["Approve","Approve with Metadata Changes","Request Revision","Reject","Escalate"]).map((item) => <option key={item}>{item}</option>)}</select></Field><Field label="Review reason"><textarea value={reason} onChange={(e) => setReason(e.target.value)} /></Field></div><button className="ingestion-primary" onClick={() => { const result = type === "technical" ? ingestionService.completeTechnicalReview(record.id, decision, checklist, reason, user) : ingestionService.completeCatalogReview(record.id, decision, checklist, reason, user); showToast(result.ok ? `${type === "technical" ? "Technical" : "Catalog"} review saved.` : result.message); if (result.ok) refresh(); }}>Complete review</button></>;
}

function RevisionPanel({ record, refresh, showToast }) {
  const { user } = useAuth(); const [form,setForm] = useState({ title:"",requestedChanges:"",affectedSections:["Audio Assets"],requiredFiles:[],artistMessage:"",internalNotes:"",dueDate:"",priority:"High",assignedRespondent:record.submittedBy });
  return <><div className="ingestion-form-grid"><Field label="Request title"><input value={form.title} onChange={(e)=>setForm({...form,title:e.target.value})}/></Field><Field label="Due date"><input type="date" value={form.dueDate} onChange={(e)=>setForm({...form,dueDate:e.target.value})}/></Field><Field label="Artist-visible message"><textarea value={form.artistMessage} onChange={(e)=>setForm({...form,artistMessage:e.target.value})}/></Field><Field label="Internal notes"><textarea value={form.internalNotes} onChange={(e)=>setForm({...form,internalNotes:e.target.value})}/></Field></div><button className="ingestion-primary" onClick={()=>{const result=ingestionService.requestRevision(record.id,form,user);showToast(result.ok?"Revision requested.":result.message);if(result.ok)refresh();}}>Request revision</button><div className="revision-list">{record.revisionRequests.map((item)=><article key={item.id}><StatusBadge status={item.status}/><h3>{item.title}</h3><p>{item.artistMessage}</p><small>Due {item.dueDate || "not set"} · {item.priority}</small></article>)}</div></>;
}

function FinalApprovalPanel({ record, refresh, showToast }) {
  const { user } = useAuth(); const readiness = ingestionService.calculateReadiness(record); const [restrictions,setRestrictions] = useState(record.restrictions || []); const [reason,setReason] = useState(""); const [override,setOverride] = useState(false); const [rejection,setRejection] = useState({artistReason:"",internalRationale:"",reapplicationAllowed:true,retainAssets:true});
  return <><div className="ingestion-readiness-grid"><ReadinessCard label="Technical" readiness={readiness.technical}/><ReadinessCard label="Metadata" readiness={readiness.metadata}/><ReadinessCard label="Rights" readiness={readiness.rights}/><ReadinessCard label="Search" readiness={readiness.search}/><ReadinessCard label="Publication" readiness={readiness.publication}/></div>{readiness.publication.blockers.map((item)=><div className="ingestion-blocker" key={item}><WarningCircle/>{item}</div>)}<div className="ingestion-form-grid"><Field label="Approval restrictions"><MultiInput value={restrictions} onChange={setRestrictions} placeholder="Preview only, Manual licence review"/></Field><Field label="Decision / override reason"><textarea value={reason} onChange={(e)=>setReason(e.target.value)}/></Field><label className="ingestion-checkbox"><input type="checkbox" checked={override} onChange={(e)=>setOverride(e.target.checked)}/>Use super-administrator override</label></div><div className="ingestion-actions"><button className="ingestion-primary" onClick={()=>{const result=ingestionService.approveIngestion(record.id,restrictions,reason,user,override);showToast(result.ok?"Ingestion approved.":result.message);if(result.ok)refresh();}}>Approve{restrictions.length?" with restrictions":""}</button></div><section className="ingestion-panel rejection-panel"><h3>Reject submission</h3><Field label="Artist-facing reason"><textarea value={rejection.artistReason} onChange={(e)=>setRejection({...rejection,artistReason:e.target.value})}/></Field><Field label="Internal rationale"><textarea value={rejection.internalRationale} onChange={(e)=>setRejection({...rejection,internalRationale:e.target.value})}/></Field><button className="danger" onClick={()=>{const result=ingestionService.rejectIngestion(record.id,rejection,user);showToast(result.ok?"Submission rejected.":result.message);if(result.ok)refresh();}}>Reject and preserve history</button></section></>;
}

function PublicationPanel({ record, refresh, showToast }) {
  const { user }=useAuth(); const [schedule,setSchedule]=useState({date:"",time:"09:00",timeZone:"Europe/London",accessTier:"Professional",featured:false,announcement:true}); const [reason,setReason]=useState("");
  return <><div className="ingestion-form-grid"><Field label="Publication date"><input type="date" value={schedule.date} onChange={(e)=>setSchedule({...schedule,date:e.target.value})}/></Field><Field label="Time"><input type="time" value={schedule.time} onChange={(e)=>setSchedule({...schedule,time:e.target.value})}/></Field><Field label="Time zone"><select value={schedule.timeZone} onChange={(e)=>setSchedule({...schedule,timeZone:e.target.value})}><option>Europe/London</option><option>America/New_York</option><option>Asia/Kolkata</option><option>UTC</option></select></Field><Field label="Access tier"><select value={schedule.accessTier} onChange={(e)=>setSchedule({...schedule,accessTier:e.target.value})}><option>Discovery</option><option>Professional</option><option>VIP</option></select></Field></div><div className="ingestion-actions"><button onClick={()=>{const result=ingestionService.schedulePublication(record.id,schedule,user);showToast(result.ok?"Publication scheduled.":result.message);if(result.ok)refresh();}}>Schedule publication</button><button className="ingestion-primary" onClick={()=>{const result=ingestionService.publishTrack(record.id,user,reason);showToast(result.ok?"Track published and search synchronized.":result.message);if(result.ok)refresh();}}>Publish now</button></div><Field label="Required reason for override or unpublish"><textarea value={reason} onChange={(e)=>setReason(e.target.value)}/></Field>{record.status==="Published"&&<button className="danger" onClick={()=>{const result=ingestionService.unpublishTrack(record.id,{reason,searchBehavior:"Hidden",previewRemains:false,projectsRetainReferences:true},user);showToast(result.ok?"Track unpublished; existing licences preserved.":result.message);if(result.ok)refresh();}}>Unpublish</button>}{["Unpublished","Rejected","Withdrawn","Processing Failed"].includes(record.status)&&<button onClick={()=>{const result=ingestionService.archiveTrack(record.id,reason||"Other",user);showToast(result.ok?"Track archived with history preserved.":result.message);if(result.ok)refresh();}}><Archive/> Archive</button>}</>;
}

export function IngestionWorkspace({ navigate, showToast }) {
  const { user }=useAuth(); const id=window.localStorage.getItem(SELECTED_INGESTION_KEY); const [record,setRecord]=useState(()=>ingestionService.getById(id)); const [tab,setTab]=useState("Overview"); const refresh=()=>setRecord(ingestionService.getById(id));
  if(!record)return <section className="ingestion-page"><div className="ingestion-empty"><WarningCircle/><h2>Ingestion record not found</h2><button onClick={()=>navigate("admin-ingestion")}>Return to queue</button></div></section>;
  const readiness=ingestionService.calculateReadiness(record); const reviewerName=(id)=>REVIEWERS.find((item)=>item.id===id)?.name||"Unassigned";
  let content;
  if(tab==="Overview")content=<><div className="ingestion-readiness-grid"><ReadinessCard label="Completeness" readiness={readiness.completeness}/><ReadinessCard label="Technical" readiness={readiness.technical}/><ReadinessCard label="Metadata" readiness={readiness.metadata}/><ReadinessCard label="Rights" readiness={readiness.rights}/><ReadinessCard label="Search" readiness={readiness.search}/><ReadinessCard label="Publication" readiness={readiness.publication}/></div><div className="ingestion-two-column"><section className="ingestion-panel"><h3>Operational summary</h3><dl><dt>Source</dt><dd>{record.source}</dd><dt>Submitted by</dt><dd>{record.submittedBy}</dd><dt>Catalog reviewer</dt><dd>{reviewerName(record.assignedCatalogReviewer)}</dd><dt>Rights reviewer</dt><dd>{reviewerName(record.assignedRightsReviewer)}</dd><dt>Technical reviewer</dt><dd>{reviewerName(record.assignedAudioReviewer)}</dd></dl></section><section className="ingestion-panel"><h3>Reviewer assignment</h3>{[["assignedCatalogReviewer","Catalog reviewer"],["assignedRightsReviewer","Rights reviewer"],["assignedAudioReviewer","Technical reviewer"]].map(([key,label])=><Field key={key} label={label}><select value={record[key]||""} onChange={(e)=>{ingestionService.assignReviewers(record.id,{[key]:e.target.value},user);refresh();}}><option value="">Unassigned</option>{REVIEWERS.map((item)=><option key={item.id} value={item.id}>{item.name} — {item.team}</option>)}</select></Field>)}<Field label="Priority"><select value={record.priority} onChange={(e)=>{ingestionService.assignReviewers(record.id,{priority:e.target.value},user);refresh();}}><option>Standard</option><option>High</option><option>Urgent</option><option>Critical</option></select></Field></section></div></>;
  else if(tab==="Audio Assets")content=<AudioStep record={record} refresh={refresh} showToast={showToast}/>;
  else if(tab==="Processing Jobs")content=<JobsPanel record={record} refresh={refresh} showToast={showToast}/>;
  else if(tab==="Metadata")content=<MetadataStep record={record} setRecord={(next)=>{setRecord(next);ingestionService.saveStep(record.id,record.lastStep||1,{metadata:next.metadata},user);}}/>;
  else if(tab==="Contributors")content=<ContributorsStep record={record} refresh={refresh} showToast={showToast}/>;
  else if(tab==="Rights Declaration")content=<RightsStep record={record} setRecord={setRecord} saveRights={(declaration)=>{ingestionService.updateRightsDeclaration(record.id,declaration,user);refresh();}}/>;
  else if(tab==="Artwork and Lyrics")content=<ArtworkLyricsStep record={record} setRecord={(next)=>{setRecord(next);ingestionService.saveStep(record.id,1,{artwork:next.artwork,lyrics:next.lyrics},user);}} uploadArtwork={()=>{ingestionService.uploadMockAsset(record.id,"Valid artwork",user);ingestionService.saveStep(record.id,1,{artwork:{status:"Uploaded",fileName:"track-artwork.webp",width:2400,height:2400}},user);refresh();}}/>;
  else if(tab==="Delivery Assets")content=<DeliveryStep record={record} setRecord={(next)=>{setRecord(next);ingestionService.saveStep(record.id,1,{deliveryAssets:next.deliveryAssets},user);}}/>;
  else if(tab==="Technical Review")content=<ChecklistPanel type="technical" record={record} refresh={refresh} showToast={showToast}/>;
  else if(tab==="Catalog Review")content=<ChecklistPanel type="catalog" record={record} refresh={refresh} showToast={showToast}/>;
  else if(tab==="Rights Readiness")content=<><ReadinessCard label="Rights readiness" readiness={readiness.rights}/>{readiness.rights.blockers.map((item)=><div className="ingestion-blocker" key={item}><WarningCircle/>{item}</div>)}<div className="ingestion-actions"><button onClick={()=>navigate("admin-rights-track")}>Open Rights Record</button><button onClick={()=>{const result=ingestionService.requestRightsReview(record.id,user);showToast(result.ok?"Rights review requested.":result.message);refresh();}}>Request Rights Review</button></div></>;
  else if(tab==="Search Readiness")content=<><ReadinessCard label="Search readiness" readiness={readiness.search}/><section className="ingestion-panel"><h3>Buyer-safe result preview</h3><p><strong>{record.metadata.title}</strong> · {record.metadata.artist}</p><p>{record.metadata.primaryGenre} · {(record.metadata.moods||[]).join(", ")}</p><StatusBadge status={record.searchReadiness.status}/><p>Unpublished records remain excluded from buyer suggestions, facets, counts, collections, and results.</p></section></>;
  else if(tab==="Revision Requests")content=<RevisionPanel record={record} refresh={refresh} showToast={showToast}/>;
  else if(tab==="Internal Notes")content=<section className="ingestion-panel"><h3>Permission-restricted notes</h3>{record.internalNotes.map((note)=><article key={note.id}><strong>{note.author} · {note.visibility}</strong><p>{note.content}</p></article>)}<p>Internal notes never appear in the artist workspace or buyer catalog.</p></section>;
  else if(tab==="Activity")content=<div className="ingestion-timeline">{record.activity.map((item)=><article key={item.id}><span/><div><strong>{item.action}</strong><p>{item.description}</p><small>{item.actor} · {item.visibility} · {new Date(item.timestamp).toLocaleString()}</small></div></article>)}</div>;
  else if(tab==="Final Approval")content=<FinalApprovalPanel record={record} refresh={refresh} showToast={showToast}/>;
  else if(tab==="Publication")content=<PublicationPanel record={record} refresh={refresh} showToast={showToast}/>;
  else content=<ReviewStep record={record}/>;
  return <section className="ingestion-page ingestion-workspace"><button className="ingestion-back" onClick={()=>navigate("admin-ingestion")}><ArrowLeft/> Ingestion queue</button><PageHeader eyebrow={`${record.reference||"Draft"} · ${record.source}`} title={record.trackTitle} text={`${record.artistName} · ${record.currentStage} · Updated ${new Date(record.updatedAt).toLocaleString()}`} actions={<StatusBadge status={record.status}/>} /><ProgressTracker record={record}/><nav className="ingestion-workspace-tabs" aria-label="Ingestion workspace sections">{workspaceTabs.map((item)=><button key={item} className={tab===item?"active":""} onClick={()=>setTab(item)}>{item}</button>)}</nav><main className="ingestion-workspace-content"><h3>{tab}</h3>{content}</main></section>;
}

export function renderIngestionView(view, props) {
  if(view==="artist-submissions")return <ArtistSubmissions {...props}/>;
  if(view==="artist-submission-new")return <TrackSubmissionWizard {...props}/>;
  if(view==="artist-submission-detail")return <ArtistSubmissionDetail {...props}/>;
  if(view==="admin-ingestion")return <IngestionDashboard {...props}/>;
  if(view==="admin-ingestion-new")return <TrackSubmissionWizard {...props} internalMode/>;
  return <IngestionWorkspace {...props}/>;
}
